import React, { useState, useEffect } from 'react';
import api from '../services/api';

const TYPE_STYLES = {
    practice: 'text-primary-400',
    interview: 'text-accent-400',
    gd: 'text-neon-green',
    learning: 'text-neon-yellow',
    challenge: 'text-neon-pink',
};

const FUN_COMPLETE = [
    "Mission complete! You're on fire! 🔥",
    "Grammar police approve. XP incoming! 🚔",
    "Even CEOs started with awkward first steps. You're past that! 💼",
    "Achievement unlocked! 🏆",
];

export default function MissionTracker() {
    const [missions, setMissions] = useState([]);
    const [loading, setLoading] = useState(true);
    const [completing, setCompleting] = useState(null);
    const [flash, setFlash] = useState(null);  // { missionId, msg }

    useEffect(() => {
        api.get('/api/missions/daily')
            .then(res => setMissions(res.data || []))
            .catch(() => {
                // Demo missions
                setMissions([
                    { id: 'm1', title: 'Morning Warm-Up 🌅', description: 'Record a 60-second speech', type: 'practice', xpReward: 50, icon: '🎤', completed: false },
                    { id: 'm2', title: 'Interview Hero 💼', description: 'Answer one HR question', type: 'interview', xpReward: 75, icon: '⭐', completed: false },
                    { id: 'm3', title: 'Group Thinker 🤝', description: 'Join a group discussion', type: 'gd', xpReward: 100, icon: '👥', completed: false },
                    { id: 'm4', title: 'Learn Something New 📚', description: 'Watch a learning video', type: 'learning', xpReward: 30, icon: '🎬', completed: false },
                    { id: 'm5', title: 'Challenge Accepted 🔥', description: 'Complete any speaking challenge', type: 'challenge', xpReward: 80, icon: '🏆', completed: false },
                ]);
            })
            .finally(() => setLoading(false));
    }, []);

    const handleComplete = async (mission) => {
        if (mission.completed || completing === mission.id) return;
        setCompleting(mission.id);
        try {
            await api.post(`/api/missions/${mission.id}/complete`);
        } catch { /* optimistic anyway */ }
        setMissions(prev => prev.map(m => m.id === mission.id ? { ...m, completed: true } : m));
        const msg = FUN_COMPLETE[Math.floor(Math.random() * FUN_COMPLETE.length)];
        setFlash({ missionId: mission.id, msg });
        setTimeout(() => setFlash(null), 3000);
        setCompleting(null);
    };

    const completed = missions.filter(m => m.completed).length;
    const totalXP = missions.reduce((s, m) => s + (m.completed ? 0 : m.xpReward), 0);

    if (loading) {
        return (
            <div className="glass-card p-5 space-y-3 animate-pulse">
                <div className="h-4 rounded bg-white/5 w-40" />
                {[1, 2, 3].map(i => <div key={i} className="h-14 rounded-xl bg-white/5" />)}
            </div>
        );
    }

    return (
        <div className="glass-card p-5 space-y-4">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h3 className="text-white font-semibold text-sm">🎯 Daily Missions</h3>
                    <p className="text-white/40 text-xs">{completed}/{missions.length} done · {totalXP} XP available</p>
                </div>
                {/* Progress bubbles */}
                <div className="flex gap-1">
                    {missions.map(m => (
                        <div key={m.id} className={`w-2 h-2 rounded-full transition-all duration-300
                            ${m.completed ? 'bg-neon-green' : 'bg-white/15'}`} />
                    ))}
                </div>
            </div>

            {/* Mission list */}
            <div className="space-y-2">
                {missions.map(mission => (
                    <div key={mission.id} className={`flex items-center gap-3 px-3 py-2.5 rounded-xl border
                        transition-all duration-200
                        ${mission.completed
                            ? 'bg-neon-green/5 border-neon-green/20 opacity-60'
                            : 'bg-white/3 border-white/8 hover:border-white/15'}`}
                    >
                        <div className="text-xl flex-shrink-0">{mission.icon}</div>
                        <div className="flex-1 min-w-0">
                            <p className={`text-xs font-semibold truncate ${mission.completed ? 'line-through text-white/40' : 'text-white'}`}>
                                {mission.title}
                            </p>
                            <p className="text-white/40 text-[10px] truncate">{mission.description}</p>
                        </div>
                        <div className="flex items-center gap-2 flex-shrink-0">
                            <span className="text-neon-green font-bold text-xs">+{mission.xpReward}</span>
                            {mission.completed ? (
                                <div className="w-5 h-5 rounded-full bg-neon-green/20 flex items-center justify-center">
                                    <span className="text-neon-green text-[10px]">✓</span>
                                </div>
                            ) : (
                                <button
                                    onClick={() => handleComplete(mission)}
                                    disabled={completing === mission.id}
                                    className="w-5 h-5 rounded-full border-2 border-white/20 hover:border-neon-green
                                               hover:bg-neon-green/10 transition-all duration-200 flex-shrink-0"
                                />
                            )}
                        </div>
                    </div>
                ))}
            </div>

            {/* Flash message */}
            {flash && (
                <div className="p-2 rounded-xl bg-neon-green/10 border border-neon-green/20 text-neon-green text-xs text-center animate-fadeInUp">
                    {flash.msg}
                </div>
            )}
        </div>
    );
}
